.sy-controls li a::after { content: ""; background-image: url("../images/arrows.svg"); background-repeat: no-repeat; background-size: cover; text-align: center; text-indent: 0px; line-height: 2.8em; color: rgb(17, 17, 17); font-weight: 800; position: absolute; width: 2.8em; height: 2.8em; left: 50%; top: 50%; margin-top: -1.4em; margin-left: -1.4em; }
@media only screen and (max-device-width: 600px) {
  .sy-controls { display: block; }
  .sy-controls li { min-width: 2.1em; }
  .sy-controls li a::after { width: 1.4em; height: 1.4em; margin-top: -0.7em; margin-left: -0.7em; }
}
.sy-caption-wrap { position: absolute; top: 46%; z-index: 12; left: 50%; }
.sy-caption-wrap .sy-caption { position: relative; left: -50%; background-color: rgba(0, 0, 0, 0.3); color: rgb(255, 255, 255); padding: 0.4em 1em; text-align: center; font-size: 20px; }
.sy-caption-wrap .sy-caption a:link, .sy-caption-wrap .sy-caption a:visited { color: rgb(226, 75, 112); font-weight: 600; text-decoration: none; }
.sy-caption-wrap .sy-caption a:hover, .sy-caption-wrap .sy-caption a:focus { text-decoration: underline; }
.sy-slide .caption-head { height: auto; position: absolute; top: 3%; right: 0px; left: 0px; }
.sy-slide .caption-head h4 { }
.sy-slide .caption-head span { display: inline-block; color: rgb(238, 52, 35); font-weight: 600; }
.sy-slide .caption-head a { background-color: rgb(238, 52, 35); color: rgb(255, 255, 255); padding: 7px 20px; text-decoration: none; border: 1px solid rgb(238, 52, 35); }
.sy-slide .caption-head a:hover { background-color: rgb(255, 255, 255); color: rgb(238, 52, 35); padding: 7px 20px; border: 1px solid rgb(238, 52, 35); }
@media only screen and (max-device-width: 600px), screen and (max-width: 600px) {
  .sy-caption-wrap { left: 0px; bottom: 0.4em; }
  .sy-caption-wrap .sy-caption { left: 0px; padding: 0.2em 0.4em; font-size: 0.92em; border-radius: 0px; }
}
.sy-pager { clear: both; display: block; width: 100%; margin: 1em 0px 0px; padding: 0px; list-style: none; text-align: center; }
.sy-pager li { display: inline-block; width: 1.2em; height: 1.2em; margin: 0px 1em 0px 0px; border-radius: 50%; }
.sy-pager li.sy-active a { background-color: rgb(226, 75, 112); }
.sy-pager li a { width: 100%; height: 100%; display: block; background-color: rgb(204, 204, 204); text-indent: -9999px; background-size: 2em; border-radius: 50%; }
.sy-pager li a:link, .sy-pager li a:visited { opacity: 1; }
.sy-pager li a:hover, .sy-pager li a:focus { opacity: 0.6; }
.sy-filler { width: 100%; }
.sy-filler.ready { transition: padding 600ms; }
